<?php
namespace App\Models;
use App\Enums\LoanStatus;use App\Models\Concerns\BelongsToTenant;use App\Models\Concerns\HasAuditTrail;use Illuminate\Database\Eloquent\Concerns\HasUlids;use Illuminate\Database\Eloquent\Model;use Illuminate\Database\Eloquent\Relations\BelongsTo;use Illuminate\Database\Eloquent\Relations\HasMany;
class Loan extends Model{use BelongsToTenant,HasAuditTrail,HasUlids;protected $fillable=['cooperative_id','loan_application_id','member_id','loan_product_id','loan_number','principal_minor','interest_minor','charges_added_minor','repayable_minor','outstanding_minor','status','disbursed_at','maturity_date'];protected function casts():array{return ['principal_minor'=>'integer','interest_minor'=>'integer','charges_added_minor'=>'integer','repayable_minor'=>'integer','outstanding_minor'=>'integer','status'=>LoanStatus::class,'disbursed_at'=>'date','maturity_date'=>'date'];}public function application():BelongsTo{return $this->belongsTo(LoanApplication::class,'loan_application_id');}public function installments():HasMany{return $this->hasMany(LoanRepaymentInstallment::class);}public function charges():HasMany{return $this->hasMany(LoanCharge::class);}}
